defmodule BankAccount do
  use GenServer

  # Client API

  def start_link(balance) do
    GenServer.start_link(__MODULE__, {:ok, balance}, name: __MODULE__)
  end

  def deposit(amount) do
    GenServer.call(__INFO__, {:deposit, amount})
  end

  def withdraw(amount) do
    GenServer.call(__INFO__, {:withdraw, amount})
  end

  def balance() do
    GenServer.call(__INFO__, :balance)
  end

  # Server Callbacks

  @impl true
  def init({:ok, balance}) do
    {:ok, %{account: balance}}
  end

  @impl true
  def handle_call({:deposit, amount}, _from, state) do
    case Ets.lookup(:bank_accounts, account: state[:account]) do
      {ok, old_balance} ->
        new_balance = old_balance + amount
        Ets.insert(:bank_accounts, id: state[:account], balance: new_balance)
        {:reply, {:ok, new_balance}, state}

      error ->
        {:error, "Account not found"}
    end
  end

  @impl true
  def handle_call({:withdraw, amount}, _from, state) do
    case Ets.lookup(:bank_accounts, account: state[:account]) do
      {ok, old_balance} ->
        new_balance = old_balance - amount
        if new_balance >= 0 do
          Ets.insert(:bank_accounts, id: state[:account], balance: new_balance)
          {:reply, {:ok, new_balance}, state}
        else
          {:error, "Insufficient funds"}
        end

      error ->
        {:error, "Account not found"}
    end
  end

  @impl true
  def handle_call(:balance, _from, state) do
    Ets.lookup(:bank_accounts, account: state[:account]) |> Map.fetch!(:balance)
  end
